CREATE OR REPLACE FUNCTION fpa_get_crem_depbal (as_memno text) RETURNS bigint AS $body$
DECLARE

ldc_bal sc_dep_m_creditor.deposit_balance%type;

BEGIN

    begin
        select coalesce( sum(deposit_balance), 0 )    into STRICT ldc_bal
        from sc_dep_m_creditor@db_crem
        where 1=1
        and deposit_balance > 0
        and membership_no = as_memno
;
    exception
    when others then return 0;
    end;

  return ldc_bal;
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
